INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-ea72210e-moex-00010', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-13504c0c', 'sub-diplomatic-ea72210e-01', NULL, 'single_choice', '「身為偉大的候鳥族群，我們是活在北方凍土帶的環頸鴴……皮諾查下意識裡一直 認為，這些不肯回去的環頸鴴，已嚴重地觸犯祖先的規範，他們的行徑全然是他種 留鳥的習性，汙蔑了所有環頸鴴。但環頸鴴是和平的鳥類，縱使犯了這麼大的忤逆 罪，他們仍尊重這些『留鳥』的選擇。不過，部族的長老們憂心地意識到，這是明 顯的退化；他們若不繼續維持兩地來去的傳統，環頸鴴將無法和其他同型的鴴鷸科 水鳥競爭，未來有可能導致滅族的危機。過去，受到傳統教育的訓示，回到北方的 環頸鴴們也恥於談留鳥環頸鴴的問題。雖然他們在南方經常與留鳥一起相處，候鳥 們甚少細心探究過留鳥的形成原由。久而久之，每到春天後，就有一群留鳥滯留南 方，繁衍下一代。他們形成另一種傳統，對候鳥的遷徙反而覺得不可思議。」 有關上文形式與內涵，下列敘述何者正確？', '["文中具體展現了人類與動物的互動", "強調人類對「自然」已然造成某些改變與影響的事實", "作者在環頸鴴的行為與習性的基礎上賦予其「人格」，藉此揣測候鳥、留鳥之謎", "上文主旨在於藉由鳥類的視角演繹人類的價值觀，並非帶領讀者理解環頸鴴的 生態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:37+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00011', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'essay', '在國際法上，不屬於「國家領土」的地區有那些？有那些國際規範？試
