  ('diplomatic-ea72210e-moex-00012', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'essay', '2022 年 3月 2 日第 5 屆聯合國環境大會通過名為《終結塑膠污染：制定
具法律拘束力的國際文件》的決議，決議中確認塑膠污染應包含微塑膠，
並特別關注塑膠污染對海洋環境造成的衝擊。決議同時也強調海洋及其
他環境中的塑膠污染具有跨境的特性，不僅影響全球生態環境，同時也
危害全體人類健康。請依《聯合國海洋法公約》說明海洋環境污染與海
洋環境維護的規定。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00013', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'essay', '國際法院如何定位和應用海洋劃界的方法論？請舉例說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00014', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '關於｢國際法｣與「國內法」的關係，下列敘述何者錯誤？', '["就理論上而言，國際法與國內法的關係通常指向「一元論」及「二元論」二種不同的方法取徑", "我國憲法第141條規定：「中華民國之外交，應……尊重條約及聯合國憲章，……」", "一國得以國內法律或國內立法程序疏漏等理由，作為違反國際法上義務之正當理由", "一國國內法院能否直接適用國際法，很大程度取決於各該國家的憲法、法律規定及法院裁判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00015', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '依據《維也納條約法公約》對於條約所作之定義，下列何者非為條約？', '["京都議定書", "斯德哥爾摩人類環境宣言", "維也納外交關係公約", "馬關條約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00016', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', 'Pactatertiisnecnocentnecprosunt一詞之意義為何？', '["條約神聖原則", "需經國家同意方能使條約生效", "條約僅對締約國生效，不對第三國產生義務", "情勢發生重大且不可預見之變化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00017', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '關於「不干涉內政原則」，下列敘述何者錯誤？', '["國際法基本規則要求，一國沒有權利侵害其他國家對國內事務的管轄", "依《聯合國憲章》第7章所為的執行措施，得適用於一國國內管轄事件", "依《聯合國憲章》規定，聯合國原則上不得干涉一國國內管轄事件", "依《聯合國憲章》要求，會員國須將所有爭端依憲章提交國際法院解決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00018', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '關於國際法上的「國家繼承」，下列敘述何者錯誤？', '["1978年《關於國家在條約方面的繼承的維也納公約》，與《維也納外交關係公約》相比，前者 之爭議性較大", "1978年《關於國家在條約方面的繼承的維也納公約》為國家繼承原則之法典化成果之一", "國際法委員會於1983年已通過《關於國家在財產、檔案及債務方面的繼承的維也納公約》，但 該公約尚未生效", "國家繼承包括因交戰關係而占領等暫時性的改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00019', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-114-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '關於「人權」，下列敘述何者正確？', '["《經濟社會文化權利國際公約》並沒有提到民族（人民）自決權", "《聯合國憲章》第1條規定，聯合國設立的目的是在達成國際合作，藉以促進和鼓勵對全體人 類之人權與基本自由的尊重", "《國際人權憲章》是《公民與政治權利國際公約》及《經濟社會文化權利國際公約》二者之總稱", "人權事務屬於一國的國內管轄範圍，不適用國際法規範"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL)
